  localparam type mem_strb_t = logic [DATA_WIDTH/NUM_BANKS/8-1:0],
  /// Dependent parameter, do not override. See `axi_to_detailed_mem`, parameter `mem_id_t`.
  localparam type mem_id_t   = logic [ID_WIDTH-1:0],
