19	/// Testbench for axi_to_mem_banked. Monitors the performance for random accesses.
20	module tb_axi_to_mem_banked #(
21	  /// Data Width of the AXI4+ATOP channels.
22	  parameter int unsigned TbAxiDataWidth = 32'd256,
23	  /// Number of words of an individual memory bank.
24	  /// Determines the address width of the request output.
25	  parameter int unsigned TbNumWords     = 32'd8192,
26	  /// Number of connected memory banks.
27	  parameter int unsigned TbNumBanks     = 32'd8,
28	  /// Data width of an individual memory bank.
29	  parameter int unsigned TbMemDataWidth = 32'd64,
30	  /// Latancy in cycles of a memory bank.
31	  parameter int unsigned TbMemLatency   = 32'd2,
32	  /// Number of writes performed by the testbench.
33	  parameter int unsigned TbNumWrites    = 32'd10000,
34	  /// Number of writes performed by the testbench.
35	  parameter int unsigned TbNumReads     = 32'd10000
36	);
37	  // test bench params
38	  localparam time CyclTime = 10ns;
39	  localparam time ApplTime = 2ns;
40	  localparam time TestTime = 8ns;
41	
42	  // localparam and typedefs for AXI4+ATOP
43	  localparam int unsigned AxiIdWidth   = 32'd6;
44	  localparam int unsigned AxiAddrWidth = 32'd64;
45	  localparam int unsigned AxiStrbWidth = TbAxiDataWidth / 8;
46	  localparam int unsigned AxiUserWidth = 32'd4;
47	
48	  typedef logic [AxiAddrWidth-1:0] axi_addr_t;
49	
50	  // AXI test defines
51	  typedef axi_test::axi_rand_master #(
52	    // AXI interface parameters
53	    .AW ( AxiAddrWidth ),
54	    .DW ( TbAxiDataWidth ),
55	    .IW ( AxiIdWidth   ),
56	    .UW ( AxiUserWidth ),
57	    // Stimuli application and test time
58	    .TA ( ApplTime     ),
59	    .TT ( TestTime     ),
60	    // Maximum number of read and write transactions in flight
61	    .MAX_READ_TXNS        (   20 ),
62	    .MAX_WRITE_TXNS       (   20 ),
63	    // Upper and lower bounds on wait cycles on Ax, W, and resp (R and B) channels
64	    .AX_MIN_WAIT_CYCLES   (    0 ),
65	    .AX_MAX_WAIT_CYCLES   (    0 ),
66	    .W_MIN_WAIT_CYCLES    (    0 ),
67	    .W_MAX_WAIT_CYCLES    (    0 ),
68	    .RESP_MIN_WAIT_CYCLES (    0 ),
69	    .RESP_MAX_WAIT_CYCLES (    0 ),
70	    // AXI feature usage
71	    .AXI_MAX_BURST_LEN    (    0 ), // maximum number of beats in burst; 0 = AXI max (256)
72	    .TRAFFIC_SHAPING      (    0 ),
73	    .AXI_EXCLS            ( 1'b0 ),
74	    .AXI_ATOPS            ( 1'b0 ),
75	    .AXI_BURST_FIXED      ( 1'b0 ),
76	    .AXI_BURST_INCR       ( 1'b1 ),
77	    .AXI_BURST_WRAP       ( 1'b0 )
78	  ) axi_rand_master_t;
79	
80	  // memory defines
81	  localparam int unsigned MemAddrWidth = $clog2(TbNumWords);
82	
83	  localparam int unsigned MemBufDepth  = 1;
84	  // addresses
85	  localparam axi_addr_t StartAddr = axi_addr_t'(64'h0);
86	  localparam axi_addr_t EndAddr   = axi_addr_t'(StartAddr + 32'd2 * TbNumWords * TbAxiDataWidth/32'd8);
87	
88	  typedef logic [MemAddrWidth-1:0]     mem_addr_t;
89	  typedef logic [5:0]                  mem_atop_t;
90	  typedef logic [TbMemDataWidth-1:0]   mem_data_t;
91	  typedef logic [TbMemDataWidth/8-1:0] mem_strb_t;
92	
93	  // sim signals
94	  logic end_of_sim;
95	
96	  // dut signals
97	  logic clk, rst_n, one_dut_active;
98	
99	  logic      [1:0]            dut_busy;
100	  logic      [TbNumBanks-1:0] mem_req;
101	  logic      [TbNumBanks-1:0] mem_gnt;
102	  mem_addr_t [TbNumBanks-1:0] mem_addr;
103	  mem_data_t [TbNumBanks-1:0] mem_wdata;
104	  mem_strb_t [TbNumBanks-1:0] mem_strb;
105	  logic      [TbNumBanks-1:0] mem_we;
106	  mem_atop_t [TbNumBanks-1:0] mem_atop;
107	  logic      [TbNumBanks-1:0] mem_rvalid;
108	  mem_data_t [TbNumBanks-1:0] mem_rdata;
109	
110	  assign one_dut_active = |dut_busy;
111	
112	  AXI_BUS_DV #(
113	    .AXI_ADDR_WIDTH ( AxiAddrWidth   ),
114	    .AXI_DATA_WIDTH ( TbAxiDataWidth ),
115	    .AXI_ID_WIDTH   ( AxiIdWidth     ),
116	    .AXI_USER_WIDTH ( AxiUserWidth   )
117	  ) mem_axi_dv (clk);
118	
119	  AXI_BUS #(
120	    .AXI_ADDR_WIDTH ( AxiAddrWidth   ),
121	    .AXI_DATA_WIDTH ( TbAxiDataWidth ),
122	    .AXI_ID_WIDTH   ( AxiIdWidth     ),
123	    .AXI_USER_WIDTH ( AxiUserWidth   )
124	  ) mem_axi ();
125	  `AXI_ASSIGN(mem_axi, mem_axi_dv)
126	
127	  // stimuli generation
128	  initial begin : proc_axi_master
129	    static axi_rand_master_t axi_rand_master = new ( mem_axi_dv );
130	    end_of_sim <= 1'b0;
131	    axi_rand_master.add_memory_region(StartAddr, EndAddr, axi_pkg::DEVICE_NONBUFFERABLE);
132	    axi_rand_master.reset();
133	    @(posedge rst_n);
134	    @(posedge clk);
135	    @(posedge clk);
136	
137	    axi_rand_master.run(TbNumReads, TbNumWrites);
138	    end_of_sim <= 1'b1;
139	  end
140	
141	  // memory banks
142	  for (genvar i = 0; i < TbNumBanks; i++) begin : gen_tc_sram
143	    tc_sram #(
144	      .NumWords    ( TbNumWords   ),
145	      .DataWidth   ( TbMemDataWidth ),
146	      .ByteWidth   ( 32'd8        ),
147	      .NumPorts    ( 32'd1        ),
148	      .Latency     ( TbMemLatency   ),
149	      .SimInit     ( "none"       ),
150	      .PrintSimCfg ( 1'b1         )
151	    ) i_tc_sram_bank (
152	      .clk_i   ( clk          ),
153	      .rst_ni  ( rst_n        ),
154	      .req_i   ( mem_req[i]   ),
155	      .we_i    ( mem_we[i]    ),
156	      .addr_i  ( mem_addr[i]  ),
157	      .wdata_i ( mem_wdata[i] ),
158	      .be_i    ( mem_strb[i]  ),
159	      .rdata_o ( mem_rdata[i] )
160	    );
161	    // always be ready
162	    assign mem_gnt[i] = 1'b1;
163	    // generate mem_rvalid signal
164	    if (TbMemLatency == 0) begin : gen_no_mem__lat
165	      assign mem_rvalid[i] = mem_req[i];
166	    end else begin : gen_mem_lat
167	      logic [TbMemLatency-1:0] mem_lat_q, mem_lat_d;
168	      `FFARN(mem_lat_q, mem_lat_d, '0, clk, rst_n)
169	      assign mem_lat_d[TbMemLatency-1] = mem_req[i];
170	      if (TbMemLatency > 1) begin
171	        for (genvar lat_i = 0; lat_i < TbMemLatency - 1; lat_i++) begin
172	          assign mem_lat_d[lat_i] = mem_lat_q[lat_i+1];
173	        end
174	      end
175	      assign mem_rvalid[i] = mem_lat_q[0];
176	    end
177	  end
178	
179	  // Clock generator
180	  clk_rst_gen #(
181	    .ClkPeriod    ( CyclTime ),
182	    .RstClkCycles ( 5        )
183	  ) i_clk_rst_gen (
184	    .clk_o  ( clk   ),
185	    .rst_no ( rst_n )
186	  );
187	
188	  // Design under test
189	  axi_to_mem_banked_intf #(
190	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
191	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
192	    .AXI_DATA_WIDTH ( TbAxiDataWidth ),
193	    .AXI_USER_WIDTH ( AxiUserWidth ),
194	    .MEM_NUM_BANKS  ( TbNumBanks     ),
195	    .MEM_ADDR_WIDTH ( MemAddrWidth ),
196	    .MEM_DATA_WIDTH ( TbMemDataWidth ),
197	    .MEM_LATENCY    ( TbMemLatency   )
198	  ) i_axi_to_mem_banked_dut (
199	    .clk_i             ( clk       ),
200	    .rst_ni            ( rst_n     ),
201	    .test_i            ( 1'b0      ),
202	    .axi_to_mem_busy_o ( dut_busy  ),
203	    .slv               ( mem_axi   ),
204	    .mem_req_o         ( mem_req   ),
205	    .mem_gnt_i         ( mem_gnt   ),
206	    .mem_add_o         ( mem_addr  ), // byte address
207	    .mem_wdata_o       ( mem_wdata ), // write data
208	    .mem_be_o          ( mem_strb  ), // byte-wise strobe
209	    .mem_atop_o        ( mem_atop  ), // atomic operation
210	    .mem_we_o          ( mem_we    ), // write enable
211	    .mem_rdata_i       ( mem_rdata )  // read data
212	  );
213	
214	  // monitoring
215	  logic aw_beat, aw_stall, w_beat, b_beat, ar_beat, ar_stall, r_beat;
216	  assign aw_beat  = mem_axi.aw_valid & mem_axi.aw_ready;
217	  assign aw_stall = mem_axi.aw_valid & !mem_axi.aw_ready;
218	  assign  w_beat  = mem_axi.w_valid  & mem_axi.w_ready;
219	  assign  b_beat  = mem_axi.b_valid  & mem_axi.b_ready;
220	  assign ar_beat  = mem_axi.ar_valid & mem_axi.ar_ready;
221	  assign ar_stall = mem_axi.ar_valid & !mem_axi.ar_ready;
222	  assign  r_beat  = mem_axi.r_valid  & mem_axi.r_ready;
223	
224	  int unsigned aw_open;
225	  int unsigned ar_open;
226	
227	  initial begin : proc_monitor
228	    automatic bit aw_new = 1;
229	    automatic bit w_new  = 1;
230	    automatic bit b_new  = 1;
231	    automatic bit ar_new = 1;
232	    automatic bit r_new  = 1;
233	
234	
235	    automatic longint      wc_cnt     = 0;
236	    automatic longint      rc_cnt     = 0;
237	    automatic longint      w_cnt      = 0;
238	    automatic longint      r_cnt      = 0;
239	
240	    automatic longint      busy_cnt;
241	    automatic longint      dut_busy_cnt [TbNumBanks];
242	    automatic real         bank_busy_percent;
243	    automatic real         axi_busy_percent;
244	    automatic real         tmp;
245	
246	    aw_open           = 0;
247	    ar_open           = 0;
248	    bank_busy_percent = 0;
249	    axi_busy_percent  = 0;
250	    for (int i = 0; i < TbNumBanks; i++) begin
251	      dut_busy_cnt[i] = 0;
252	    end
253	    $display("###############################################################################");
254	    $display("Sim Parameter:");
255	    $display("###############################################################################");
256	    $display("TbAxiDataWidth: %0d", TbAxiDataWidth);
257	    $display("TbMemDataWidth: %0d", TbMemDataWidth);
258	    $display("TbNumBanks:     %0d", TbNumBanks);
259	    $display("TbMemLatency:   %0d", TbMemLatency);
260	    $display("###############################################################################");
261	
262	    @(posedge rst_n);
263	    forever begin
264	      @(posedge clk);
265	
266	      #TestTime;
267	      // determine the first valid of an AW transaction
268	      if (mem_axi.aw_valid) begin
269	        if (aw_new) begin
270	          aw_open++;
271	          if (!mem_axi.aw_ready) begin
272	            aw_new = 0;
273	          end
274	        end else begin
275	          if (mem_axi.aw_ready) begin
276	            aw_new = 1;
277	          end
278	        end
279	      end
280	
281	      // determine the first valid of an AR transaction
282	      if (mem_axi.ar_valid) begin
283	        if (ar_new) begin
284	          ar_open++;
285	          if (!mem_axi.ar_ready) begin
286	            ar_new = 0;
287	          end
288	        end else begin
289	          if (mem_axi.ar_ready) begin
290	            ar_new = 1;
291	          end
292	        end
293	      end
294	
295	      if (b_beat) begin
296	        aw_open--;
297	      end
298	      if (r_beat && mem_axi.r_last) begin
299	        ar_open--;
300	      end
301	
302	      if (aw_open > 0) begin
303	        wc_cnt++;
304	      end
305	      if (ar_open > 0) begin
306	        rc_cnt++;
307	      end
308	
309	      if (w_beat) begin
310	        w_cnt++;
311	      end
312	      if (r_beat) begin
313	        r_cnt++;
314	      end
315	
316	      if ((aw_open > 0) || (ar_open > 0)) begin
317	        busy_cnt++;
318	      end
319	
320	      for (int unsigned i = 0; i < TbNumBanks; i++) begin
321	        if (mem_req[i]) begin
322	          dut_busy_cnt[i]++;
323	        end
324	      end
325	
326	
327	      if (end_of_sim) begin
328	        @(posedge clk);
329	        $display("###############################################################################");
330	        $display("Statistics:");
331	        $display("###############################################################################");
332	        $display("Writes:");
333	        $display("Cycles Open write tnx: %0d", wc_cnt);
334	        $display("Write beat count:      %0d", w_cnt);
335	        $display("Write utilization:     %0f", real'(w_cnt) / real'(wc_cnt) * 100);
336	        axi_busy_percent += real'(w_cnt) / real'(wc_cnt) * 100;
337	                $display("###############################################################################");
338	        $display("Reads:");
339	        $display("Cycles Open read tnx:  %0d", rc_cnt);
340	        $display("Read beat count:       %0d", r_cnt);
341	        $display("Read utilization:      %0f", real'(r_cnt) / real'(rc_cnt) * 100);
342	        axi_busy_percent += real'(r_cnt) / real'(rc_cnt) * 100;
343	        $display("###############################################################################");
344	        for (int unsigned i = 0; i < TbNumBanks; i++) begin
345	          bank_busy_percent += real'(dut_busy_cnt[i]) / real'(busy_cnt) * 100;
346	          $display("Bank %0d utilization: %0f", i, real'(dut_busy_cnt[i]) / real'(busy_cnt) * 100);
347	          tmp = dut_busy_cnt[i];
348	          $display("Bank %0d requests: %0f", i, tmp);
349	          tmp = busy_cnt;
350	          $display("Bank %0d busy cycles: %0f", i, tmp);
351	        end
352	        $display("Sum bank utilization:      %0f", bank_busy_percent);
353	        $display("Sum axi utilization:       %0f", axi_busy_percent);
354	        $display("###############################################################################");
355	        $stop();
356	      end
357	    end
358	  end
359	
360	  initial begin : proc_sim_progress
361	    longint unsigned       ActAwTnx;
362	    longint unsigned       ActArTnx;
363	    automatic int unsigned PrintInterv = 100;
364	
365	    ActAwTnx = 0;
366	    ActArTnx = 0;
367	    $display("Start Addr: %0h", StartAddr);
368	    $display("End   addr: %0h", EndAddr);
369	
370	    @(posedge rst_n);
371	    forever begin
372	      @(posedge clk);
373	      #TestTime;
374	
375	      if (aw_beat) begin
376	        if (ActAwTnx % PrintInterv == 0) begin
377	          $display("%t > AW Transaction %d of %d ", $time(), ActAwTnx, TbNumWrites);
378	        end
379	        ActAwTnx++;
380	      end
381	      if (ar_beat) begin
382	        if (ActArTnx % PrintInterv == 0) begin
383	          $display("%t > AR Transaction %d of %d ", $time(), ActArTnx, TbNumReads);
384	        end
385	        ActArTnx++;
386	      end
387	
388	      if (end_of_sim) begin
389	        break;
390	      end
391	    end
392	  end
393	
394	  AXI_BUS_DV #(
395	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
396	    .AXI_DATA_WIDTH ( TbAxiDataWidth ),
397	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
398	    .AXI_USER_WIDTH ( AxiUserWidth )
399	  ) monitor_dv (clk);
400	
401	  `AXI_ASSIGN_MONITOR(monitor_dv, mem_axi)
402	
403	  typedef axi_test::axi_scoreboard #(
404	    .IW ( AxiIdWidth   ),
405	    .AW ( AxiAddrWidth ),
406	    .DW ( TbAxiDataWidth ),
407	    .UW ( AxiUserWidth ),
408	    .TT ( TestTime     )
409	  ) axi_scoreboard_t;
410	  axi_scoreboard_t axi_scoreboard = new(monitor_dv);
411	  initial begin : proc_scoreboard
412	    axi_scoreboard.enable_all_checks();
413	    @(posedge rst_n);
414	    axi_scoreboard.monitor();
415	    wait (end_of_sim);
416	  end
